-- Object: PROCEDURE dbo.GLOBAL_DATA
-- Server: 10.253.33.91 | DB: MSAJAG
--------------------------------------------------

--EXEC GLOBAL_DATA_TEST 'A124049','A124049','01 JUN 2018','31 JUL 2018','','','NSE','S','GDS'--EXEC GLOBAL_DATA_TEST 'A124049','A124049','01 JUN 2018','31 JUL 2018','','','NSE','D','GDS'CREATE  PROCEDURE [dbo].[GLOBAL_DATA](@FROMPARTY VARCHAR(20),@TOPARTY VARCHAR(20),@FROMDATE DATETIME,@TODATE DATETIME,@FROMSCRIP VARCHAR(20),@TOSCRIP VARCHAR(20),@CONSOL VARCHAR(10),   ---10  CONSOL INDICATES THAT WHETHER IS "NSE","BSE","NSEFO"@DATATYPE VARCHAR(10) ,@SBTAG VARCHAR(15))AS IF @FROMPARTY  ='' 
    BEGIN    SET @FROMPARTY ='A00'   END IF @TOPARTY  =''     BEGIN    SET @TOPARTY ='ZZZZZ'   END IF @FROMSCRIP  =''    BEGIN    SET @FROMSCRIP ='00'   END IF @TOSCRIP  =''     BEGIN    SET @TOSCRIP ='ZZZZZ'   END IF ISNULL(@FROMDATE,''
)  =''  OR ISNULL(@TODATE,'') =''    BEGIN	 SELECT 'INVALID DATE' AS STATUS 	END  IF @SBTAG =''  BEGIN      SELECT  'SUB BROKER CODE  REQUIRED'  AS STATUS 	 RETURN  END  DECLARE @CNTSB INT   IF (SELECT  COUNT(1)  FROM SUBBROKERS WHERE SUB_BROKER =@SBTAG) =0     BEGIN 	 SELECT    'INVALID SUBBROKER'  AS STATUS 	 RETURN     END	   SELECT  CL_CODE ,LONG_NAME INTO #CLIENT  FROM CLIENT_DETAILS WHERE SUB_BROKER =@SBTAG AND PARTY_CODE BETWEEN @FROMPARTY AND @TOPARTY CREATE INDEX  #CL ON #CLIENT (CL_CODE)IF @CONSOL = 'NSE' AND @DATATYPE = 'D' 		 BEGIN 		  SELECT 			PARTY_CODE,PARTY_NAME,SAUDA_DATE = LEFT(CONVERT(VARCHAR,SAUDA_DATE,109),11),(SETT_NO +'-'+ SETT_TYPE)AS SETT_DETAILS,SCRIP_CD,SCRIP_NAME,ISIN,			PTRADEDQTY = SUM(PQTYTRD + PQTYDEL),			ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0) AS PAVG_RATE ,			SUM(PAMTTRD+PAMTDEL)AS PURCHASE_VALUE,			STRADEDQTY = SUM(SQTYTRD + SQTYDEL),			ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0) AS SAVG_RATE ,		
	SUM(SAMTTRD+SAMTDEL )AS SVALUE ,			SUM (PQTYTRD-SQTYTRD) AS OPEN_QTY,			( CASE WHEN SUM (PQTYTRD-SQTYTRD)  =0 THEN 0 ELSE 			( ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0)- ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0)
) END ) OPEN_AVG, 			SUM(PAMTTRD+PAMTDEL)-SUM(SAMTTRD+SAMTDEL) AS AVERAGE_AMOUNT,			SUM(PAMTTRD-SAMTTRD)AS TRADING_PNL,			SUM(PAMTDEL-SAMTDEL)AS DELIVERY_PNL,			SUM(PAMTTRD-SAMTTRD)+SUM(PAMTDEL-SAMTDEL)AS TOTAL_VALUE,			TOTALBROKRAGE =SUM(PBROKTRD+SBROKTRD+PBROKDEL+SBROKDEL),			GST= SUM(SERVICE_TAX),			SUM(INS_CHRG) AS STT,			OTHER_TAX=SUM((TURN_TAX)+(SEBI_TAX)+(INS_CHRG)+(BROKER_CHRG))			,'NSE'AS EXCHANGE			FROM CMBILLVALAN  B WITH (NOLOCK)  , #CLIENT C WHERE  			SAUDA_DATE BETWEEN @FROMDATE AND @TODATE  +' 23:59'			AND C.CL_CODE = B.PARTY_CODE  			AND SCRIP_CD BETWEEN @FROMSCRIP AND @TOSCRIP			AND SUB_BROKER=  @SBTAG			GROUP BY PARTY_CODE,PARTY_NAME,SAUDA_DATE,SETT_NO,SETT_TYPE,SCRIP_CD,SCRIP_NAME,ISIN		END IF @CONSOL = 'NSE' AND  @DATATYPE = 'S' 		BEGIN            			SELECT PARTY_CODE,PARTY_NAME,SCRIP_NAME,ISIN,PTRADEDQTY = SUM(PQTYTRD + PQTYDEL),			ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0) AS PAVG_RATE ,			SUM(PAMTTRD+PAMTDEL)AS PURCHASE_VALUE,			STRADEDQTY = SUM(SQTYTRD + SQTYDEL),			ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0) AS SAVG_RATE ,			SUM(SAMTTRD+SAMTDEL )AS SVALUE ,			SUM (PQTYTRD-SQTYTRD) AS OPEN_QTY,			( CASE WHEN SUM (PQTYTRD-SQTYTRD)  =0 THEN 0 ELSE 			( ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0)- ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0)) END ) OPEN_AVG, 			SUM(PAMTTRD+PAMTDEL)-SUM(SAMTTRD+SAMTDEL) AS AVERAGE_AMOUNT,			SUM(PAMTTRD-SAMTTRD)AS TRADING_PNL,			SUM(PAMTDEL-SAMTDEL)AS DELIVERY_PNL,			SUM(PAMTTRD-SAMTTRD)+SUM(PAMTDEL-SAMTDEL)AS TOTAL_VALUE,			TOTALBROKRAGE =SUM(PBROKTRD+SBROKTRD+PBROKDEL+SBROKDEL),			GST= SUM(SERVICE_TAX),			SUM(INS_CHRG) AS STT,			OTHER_TAX=SUM((TURN_TAX)+(SEBI_TAX)+(INS_CHRG)+(BROKER_CHRG))			,'NSE'AS EXCHANGE			FROM CMBILLVALAN B WITH (NOLOCK)  , #CLIENT C WHERE     			SAUDA_DATE BETWEEN @FROMDATE AND @TODATE  +' 23:59'			AND B.PARTY_CODE =C.CL_CODE			AND SCRIP_CD BETWEEN @FROMSCRIP AND @TOSCRIP			---AND @DATATYPE='SUMMARY'			GROUP BY PARTY_CODE,PARTY_NAME,SCRIP_CD,SCRIP_NAME,ISIN		END  -------------------------BSE SEGMENT---------------IF @CONSOL = 'BSE' AND @DATATYPE = 'D' 	 BEGIN 			SELECT 			PARTY_CODE,PARTY_NAME,SAUDA_DATE = LEFT(CONVERT(VARCHAR,SAUDA_DATE,109),11),(SETT_NO +'-'+ SETT_TYPE)AS SETT_DETAILS,SCRIP_CD,SCRIP_NAME,ISIN,			PTRADEDQTY = SUM(PQTYTRD + PQTYDEL),		    ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0) AS PAVG_RATE ,			SUM(PAMTTRD+PAMTDEL)AS PURCHASE_VALUE,			STRADEDQTY = SUM(SQTYTRD + SQTYDEL),			ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0) AS SAVG_RATE ,			SUM(SAMTTRD+SAMTDEL )AS SVALUE ,			SUM (PQTYTRD-SQTYTRD) AS OPEN_QTY,			( CASE WHEN SUM (PQTYTRD-SQTYTRD)  =0 THEN 0 ELSE 			( ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0)- ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0)) END ) OPEN_AVG, 			SUM(PAMTTRD+PAMTDEL)-SUM(SAMTTRD+SAMTDEL) AS AVERAGE_AMOUNT,			SUM(PAMTTRD-SAMTTRD)AS TRADING_PNL,			SUM(PAMTDEL-SAMTDEL)AS DELIVERY_PNL,			SUM(PAMTTRD-SAMTTRD)+SUM(PAMTDEL-SAMTDEL)AS TOTAL_VALUE,			TOTALBROKRAGE =SUM(PBROKTRD+SBROKTRD+PBROKDEL+SBROKDEL),			GST= SUM(SERVICE_TAX),			SUM(INS_CHRG) AS STT,			OTHER_TAX=SUM((TURN_TAX)+(SEBI_TAX)+(INS_CHRG)+(BROKER_CHRG))			,'BSE'AS EXCHANGE			FROM AngelBSECM.BSEDB_AB.DBO.CMBILLVALAN B WITH (NOLOCK)  , #CLIENT C WHERE     			SAUDA_DATE BETWEEN @FROMDATE AND @TODATE  +' 23:59'			AND B.PARTY_CODE =C.CL_CODE			AND SCRIP_CD BETWEEN @FROMSCRIP AND @TOSCRIP			---AND @DATATYPE='DETAIL'			GROUP 
BY PARTY_CODE,PARTY_NAME,SAUDA_DATE,SETT_NO,SETT_TYPE,SCRIP_CD,SCRIP_NAME,ISIN	END IF @CONSOL = 'BSE' AND  @DATATYPE = 'S' 	BEGIN            		SELECT 		PARTY_CODE,PARTY_NAME,SCRIP_NAME,ISIN,		PTRADEDQTY = SUM(PQTYTRD + PQTYDEL),		ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0) AS PAVG_RATE ,		SUM(PAMTTRD+PAMTDEL)AS PURCHASE_VALUE,		STRADEDQTY = SUM(SQTYTRD + SQTYDEL),		ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0) AS SAVG_RATE ,		SUM(SAMTTRD+SAMTDEL )AS SVALUE ,	
	SUM (PQTYTRD-SQTYTRD) AS OPEN_QTY,		( CASE WHEN SUM (PQTYTRD-SQTYTRD)  =0 THEN 0 ELSE 		( ISNULL(SUM((PAMTTRD+PAMTDEL)/NULLIF((PQTYTRD+PQTYDEL),0) ),0)- ISNULL(SUM((SAMTTRD+SAMTDEL)/NULLIF((SQTYTRD+SQTYDEL),0) ),0)) END ) OPEN_AVG, 		SUM(PAMTTRD+PAMTDEL)-SUM(SAMTTRD+SAMTDEL) AS AVERAGE_AMOUNT,		SUM(PAMTTRD-SAMTTRD)AS TRADING_PNL,		SUM(PAMTDEL-SAMTDEL)AS DELIVERY_PNL,		SUM(PAMTTRD-SAMTTRD)+SUM(PAMTDEL-SAMTDEL)AS TOTAL_VALUE,		TOTALBROKRAGE =SUM(PBROKTRD+SBROKTRD+PBROKDEL+SBROKDEL),		GST= SUM(SERVICE_TAX),		SUM(INS_CHRG) AS STT,		OTHER_TAX=SUM((TURN_TAX)+(SEBI_TAX)+(INS_CHRG)+(BROKER_CHRG))		,'BSE'AS EXCHANGE		FROM AngelBSECM.BSEDB_AB.DBO.CMBILLVALAN B WITH (NOLOCK)  , #CLIENT C WHERE     		SAUDA_DATE BETWEEN @FROMDATE AND @TODATE  +' 23:59'		AND B.PARTY_CODE =C.CL_CODE		AND SCRIP_CD BETWEEN @FROMSCRIP AND @TOSCRIP		  ---AND @DATATYPE='SUMMARY'		GROUP BY PARTY_CODE,PARTY_NAME,SCRIP_CD,SCRIP_NAME,ISIN	END

GO
